import mapboxgl from "!mapbox-gl"; // eslint-disable-line import/no-webpack-loader-syntax
import * as React from "react";
import { useEffect, useState } from "react";
// import MapboxLanguage from "@mapbox/mapbox-gl-language";
import MapGL, {
	FlyToInterpolator,
	AttributionControl,
	FullscreenControl,
	GeolocateControl,
} from "react-map-gl";

import "./index.css";

// const mapboxApiAccessToken =
// 	"pk.eyJ1IjoiaGF0Z29yIiwiYSI6ImNrcHNpYjU4dzA0ZHkyd3Bpdnd2MXh0N2wifQ.Vu5zeZFnqeOekJVjDHC6sg";
mapboxgl.accessToken =
	"pk.eyJ1IjoiaGF0Z29yIiwiYSI6ImNrcHNpYjU4dzA0ZHkyd3Bpdnd2MXh0N2wifQ.Vu5zeZFnqeOekJVjDHC6sg";

const Map = () => {
	const [viewport, setViewport] = useState({
		width: "100%",
		height: "100%",
		latitude: 46.482526,
		longitude: 30.7233095,
		zoom: 13,
	});

	const goToNYC = () => {
		setViewport({
			...viewport,
			longitude: -74.1,
			latitude: 40.7,
			zoom: 14,
			transitionDuration: 1000,
			transitionInterpolator: new FlyToInterpolator(),
		});
	};

	// useEffect(() => {});

	return (
		<>
			<MapGL
				{...viewport}
				mapboxApiAccessToken={mapboxgl.accessToken}
				onViewportChange={(nextViewport) => setViewport(nextViewport)}
				attributionControl={false}
				dragRotate={true} // поворот карты
				touchRotate={true} // default: false
				clickRadius={10}
			>
				{/* <AttributionControl
					compact={true}
					style={{ right: 0, top: 0 }}
				/> */}
				{/* <FullscreenControl style={{ right: 10, top: 100 }} /> */}
				<GeolocateControl
					style={{ right: 15, bottom: 25 }}
					positionOptions={{ enableHighAccuracy: true }}
					trackUserLocation={true}
					auto
					fitBoundsOptions={{ maxZoom: 17 }}
				/>
				{/* console.log(viewport.zoom, viewport.transitionDuration) */}
			</MapGL>
			<button onClick={goToNYC}>New York City</button>
		</>
	);
};

export default Map;

